import{_ as b,o as e,c as a,j as p,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const M=JSON.parse('{"title":"泰拉瑞亚奇物组","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/泰拉瑞亚奇物组.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/泰拉瑞亚奇物组.md"}'),s={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/泰拉瑞亚奇物组.md"};function o(d,r,_,l,i,c){return e(),a("div",null,[...r[0]||(r[0]=[p("h1",{id:"泰拉瑞亚奇物组",tabindex:"-1"},[t("泰拉瑞亚奇物组 "),p("a",{class:"header-anchor",href:"#泰拉瑞亚奇物组","aria-label":'Permalink to "泰拉瑞亚奇物组"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风026")])])],-1),n('<h1 id="泰拉瑞亚奇物组-1" tabindex="-1">泰拉瑞亚奇物组 <a class="header-anchor" href="#泰拉瑞亚奇物组-1" aria-label="Permalink to &quot;泰拉瑞亚奇物组&quot;">​</a></h1><p>泰拉瑞亚奇物组</p><p>脚镣<br> 占据鞋袜位<br> 500</p><p>他没感到那种难忍的干渴把人的喉头填沙般地折磨<br> 尽管刽子手戴上施刑手套，走进了装着厚衬垫的门道，<br> 两只手上缠着三根皮索，勒紧喉咙使它不再知渴。</p><p>【镣铐】：这是一个坚固的镣铐，如果使用得当的话，你可以用它挡下一些攻击，因此这个奇物会为你提供2点盔甲防御。</p><p>星力手环<br> 占据手腕位<br> 250</p><p>星星是大自然之手建造的大厦，<br> 也许，受祝福的灵魂居住在那里，<br> 身着光芒，那是他们不朽的外衣；<br> 浩瀚的海洋，在它黄色的岸边，<br> 展现出一个精心设计的居所，<br> 供生命在爱与安宁中栖息……</p><p>【星力】：这是一个闪耀着星光的湛蓝手环，其中有着来自星空的力量，获得时选择一个能量池，那个能量池的上限提升3点。</p><p>魔力再生手环<br> 占据手腕位<br> 由星力手环+D+500升级而来</p><p>啊，月亮 —— 还有星星！<br> 你们如此遥远 ——<br> 但如果没有谁比你们更遥远 ——<br> 你们觉得我会因一片苍穹或一腕尺 ——<br> 左右的距离而停步吗……</p><p>【星力】：这是一个闪耀着夜光的深蓝手环，其中有着来自夜空的力量，获得时选择一个能量池，那个能量池的上限提升15点，你的攻击获得【法破】，如果你的能量池没有完全消耗，那么获得1点盔甲防御 。</p><p>魔法手铐<br> C级奇物<br> 占据手腕位<br> 由魔力再生手环和脚镣用D+500差升而来</p><p>看星星！看，仰望天空！<br> 噢，看所有那些火一般的人们坐在空中！<br> 那明亮的市镇，那环形的城堡！<br> 在昏暗的树林里，钻石的矿坑！精灵的眼睛……</p><p>【星力】：这是一个闪耀着夜光的深蓝手环，其中有着来自夜空的力量，获得时选择一个能量池，那个能量池的上限提升15点，你的攻击获得【法破】，如果你的能量池没有完全消耗，那么获得3点盔甲防御 。</p><p>【镣铐】：这是一个坚固的镣铐，如果使用得当的话，你可以用它挡下一些攻击，因此这个奇物为你提供2点盔甲防御，并且可以使用【学识-施法】来进行格挡，如果你额外支付3XP，那么你可以选择使用其他的施法检定专业来进行格挡判定，你获得灵感视觉。</p><p>鞋带束头<br> 250<br> 占据鞋袜位<br> 机灵鬼坐到桌子上，将靴子搭在奥立弗的一条腿上，开始进行被达金斯先生称作“替脚套上光”的这一道工序，也就是替他擦鞋。</p><p>【轻盈】：鞋子的舒适度十足的上升了，你的基础速度上升5M。</p><p>赫尔墨斯之靴<br> 占据鞋袜位<br> D+500</p><p>他轻松地飞翔，穿过如此广阔的天空，<br> 生命的火花，转瞬即逝的潮汐。<br> 从奥林匹斯山到地面，<br> 他的皮革翅膀，敏捷而有价值。</p><p>【带翼靴】：尽管不是真品，但是这同样是不可多得的宝物，你的基础速度上升15M。<br> 赫尔墨斯一日之内就能围绕奥林匹斯山一圈，而不觉疲惫，这和这双靴子息息相关，你免疫疲乏异常点数。<br> 如果你每轮结束时，没有进行转弯幅度超过180°的移动，那么你的移动速度上升5M，最多获得5次，如果某轮中朝反方向进行移动，立刻失去已有的移速。</p><p>疾风脚镯<br> 占据鞋袜位<br> 1000</p><p>哦，狂野的西风，秋之生命的气息，<br> 你无形，但枯死的落叶被你横扫，<br> 有如鬼魅碰到了巫师，纷纷逃避：</p><p>【疾风】：魔法的力量充盈着你的脚踝，你的基础移速上升15M。</p><p>火箭靴<br> 占据鞋袜位<br> D+500</p><p>“火箭小子在此！我可以带你飞向更高的天空！”</p><p>【喷气火箭】：你现在可以在空中以一个自由动作使用这个靴子来向下喷出大量的气体，借此来停留在空中，持续一场景，但是如果你想要提前降落，那么你需要先以一个移动动作解除悬浮状态。<br> 同时这双靴子持续喷出的气体，可以帮助你免疫坠落伤害，以及越过一些困难地形，这是一个C级的免疫困难地形效果。</p><p>幽灵靴<br> C级奇物<br> 占据鞋袜位<br> 由赫尔墨斯之靴和火箭靴合成而来</p><p>“像黄眼睛的天使，我回到你的床上，在夜的暗影中，无声无息地溜到你身旁。……正如别人待你的温存，对于你的生命和青春，我将用恐怖来管领。”</p><p>【带翼靴】：尽管不是真品，但是这同样是不可多得的宝物，你的基础速度上升15M。<br> 赫尔墨斯一日之内就能围绕奥林匹斯山一圈，而不觉疲惫，这和这双靴子息息相关，你免疫疲乏异常点数。<br> 如果你每轮结束时，没有进行转弯幅度超过180°的移动，那么你的移动速度上升5M，最多获得5次，如果某轮中朝反方向进行移动，立刻失去已有的移速。</p><p>【喷气火箭】：你现在可以在空中以一个自由动作使用这个靴子来向下喷出大量的气体，借此来停留在空中，持续一场景，但是如果你想要提前降落，那么你需要先以一个移动动作解除悬浮状态。<br> 同时这双靴子持续喷出的气体，可以帮助你免疫坠落伤害，以及越过一些困难地形，这是一个C级的免疫困难地形效果。</p><p>闪电靴<br> C级奇物<br> 占据鞋袜位<br> 由幽灵靴+疾风脚镯+鞋带束头+D+500合成而来</p><p>“束缚在云层中的闪电，我所看到的蓝色闪电，我疲惫地等待着你。我的身躯像破布一样躺卧。因为某天，我会被闪电之手抓住，比世界上的一切矿石都要坚硬，放射出闪电。”</p><p>【电闪雷鸣】：你终将声震人间，你的基础速度上升15M。<br> 你终将点燃闪电，必长久如云漂泊，你免疫疲乏异常点数。<br> 你每轮结束时，你的基础移速上升5M，最多获得5次。</p><p>【破空】：闪电是惨绿天空的一次撕裂，你获得机动性为普通的飞行能力。<br> 你免疫坠落伤害，你的行走将以贴地的方式快速移动，因此你的基础移速上升20M，并且可以免疫C级的困难地形，并且你免疫B级的迟滞效果。</p><p>溜冰鞋<br> 占据鞋袜位<br> 250</p><p>【滑冰】：如果你降落到易碎冰块上，冰块不一定会破碎。</p><p>霜花靴<br> C级奇物<br> 占据鞋袜位<br> 由闪电靴和溜冰靴合成而来</p><p>雪花如同天空洒下的羽毛，轻轻地覆盖了大地的伤痕。</p><p>【电闪雷鸣】：你终将声震人间，你的基础速度上升15M。<br> 你终将点燃闪电，必长久如云漂泊，你免疫疲乏异常点数。<br> 你每轮结束时，你的基础移速上升5M，最多获得5次。</p><p>【破空】：闪电是惨绿天空的一次撕裂，你获得机动性为普通的飞行能力。<br> 你免疫坠落伤害，你的行走将以贴地的方式快速移动，因此你的基础移速上升20M，并且可以免疫C级的困难地形，并且你免疫B级的迟滞效果。</p><p>【滑冰】：如果你降落到易碎冰块上，冰块不一定会破碎。</p><p>黑曜石骷髅头<br> 1000<br> 占据面具位</p><p>历经亿万年风霜雪雨的洗礼<br> 你是火山岩浆的凝固<br> 在黑暗中磨砺出坚硬与深邃</p><p>【黑曜石】：诞生自熔岩与水之中，这个奇物会为你带来火焰抗力2。</p><p>水上漂靴<br> 250<br> 占据鞋袜位</p><p>【水行】：你获得等同于基础移速的水面行走能力。</p><p>熔岩护身符<br> D+500<br> 占据护符位</p><p>“我是熔岩，火红色炽烈运行的集团。”<br> “我涌起、我爆炸、我喷发了，整个大地都在我的脚下震颤。”<br> “我的热情，不是鸽哨不是花坛，它像积雨云中的雷霆，像芬地湾的潮汐，升腾、创造、或者破坏。”</p><p>【熔岩】：你免疫熔岩区域地形。</p><p>黑曜石玫瑰<br> D+500<br> 占据护符位</p><p>你是万年前不朽的精灵<br> 一如不落的日月和永恒的星空<br> 是印第安女人珍珠般晶莹的泪<br> 把你洗涤的如此精黑而透明</p><p>【黑曜石】：你获得火焰抗性3，并且你获得仅针对燃烧点数的异常点治疗1（医疗点20），但是每场景中，你最多使用其中的5点医疗点，这是在长时间接触之后引起的护符过热。</p><p>熔岩靴<br> C级奇物<br> 占据鞋袜位<br> 由黑曜石玫瑰，黑曜石头骨，熔岩护身符和水上漂靴合成而来</p><p>熔岩来了，流来了，又深又厚的熔岩使田野变得肥沃，到海里修堤筑堰；海滩、海洋和海岛，一切都摇摇欲坠</p><p>【黑曜石】：诞生自熔岩与水之中，这个奇物会为你带来火焰抗力5，并且你获得仅针对燃烧点数的异常点治疗1（医疗点20）。</p><p>【熔岩】：你免疫B级困难地形。</p><p>【熔岩行】：你获得等同于基础移速的水面行走能力，特殊的，这也可以让你在熔岩上行走。</p><p>泰拉闪耀靴<br> B级奇物<br> 由熔岩靴和霜花靴合成而来<br> 占据鞋袜位</p><p>它闪耀着源自泰拉的能量！</p><p>【黑曜石】：诞生自熔岩与水之中，这个奇物会为你带来火焰抗力5，并且你获得仅针对燃烧点数的异常点治疗1（医疗点20）。</p><p>【熔岩】：你免疫B级困难地形。</p><p>【电闪雷鸣】：你终将声震人间，你的基础速度上升15M。<br> 你终将点燃闪电，必长久如云漂泊，你免疫疲乏异常点数。<br> 你每轮结束时，你的基础移速上升5M，最多获得5次。</p><p>【破空】：闪电是惨绿天空的一次撕裂，你获得机动性为普通的飞行能力。<br> 你免疫坠落伤害，你的行走将以贴地的方式快速移动，因此你的基础移速上升20M，并且可以免疫C级的困难地形，并且你免疫B级的迟滞效果。</p><p>【滑冰】：如果你降落到易碎冰块上，冰块不一定会破碎。</p><p>【熔岩行】：你获得等同于基础移速的水面行走能力，特殊的，这也可以让你在熔岩上行走。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',67)])])}const f=b(s,[["render",o]]);export{M as __pageData,f as default};
